/* CSS: Style — the skin and clothes */
article {
  background: #f9f9f9;
  padding: 1.5rem;
  border-radius: 8px;
}

button {
  background: #0070f3;
  color: white;
  border: none;
  padding: 0.5rem 1rem;
  border-radius: 4px;
  cursor: pointer;
}

// JavaScript: Behaviour — the muscles
const button = document.querySelector('button');

button.addEventListener('click', () => {
  alert('Opening the full post!');
});
